import assert from "node:assert/strict";
import { existsSync, mkdtempSync, readFileSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { afterAll, test } from "vitest";

// The reporter is plain ESM; import() accepts the resolved file:// URL directly,
// which loads identically on Windows and POSIX.
const reporterUrl = new URL("./helpers/hung-test-reporter.mjs", import.meta.url).href;
const { default: hungTestReporter } = await import(reporterUrl);

const tmpDirs: string[] = [];
afterAll(() => {
	for (const dir of tmpDirs) rmSync(dir, { recursive: true, force: true });
});

function heartbeatPath() {
	const dir = mkdtempSync(join(tmpdir(), "hb-reporter-test-"));
	tmpDirs.push(dir);
	return join(dir, "hb.json");
}

/** Drive the reporter over a fixed event list, returning the final heartbeat. */
async function drive(events: Array<{ type: string; data?: Record<string, unknown> }>, heartbeatFile: string | undefined) {
	const prev = process.env.BOBBIT_UNIT_NODE_HEARTBEAT_FILE;
	if (heartbeatFile === undefined) delete process.env.BOBBIT_UNIT_NODE_HEARTBEAT_FILE;
	else process.env.BOBBIT_UNIT_NODE_HEARTBEAT_FILE = heartbeatFile;
	async function* source() {
		for (const ev of events) yield ev;
	}
	try {
		// The reporter yields nothing; draining the generator runs it to completion
		// (including its synchronous final flush).
		for await (const _ of hungTestReporter(source())) {
			void _;
		}
	} finally {
		if (prev === undefined) delete process.env.BOBBIT_UNIT_NODE_HEARTBEAT_FILE;
		else process.env.BOBBIT_UNIT_NODE_HEARTBEAT_FILE = prev;
	}
	return heartbeatFile && existsSync(heartbeatFile) ? JSON.parse(readFileSync(heartbeatFile, "utf8")) : undefined;
}

// Windows-style file/name pairs: node reports the file-level test's `name` as the
// CLI path and its `file` as the absolute path; both must resolve to file-level.
const fileA = "C:\\repo\\tests\\alpha.test.ts";
const nameA = "tests\\alpha.test.ts";
const fileB = "C:\\repo\\tests\\beta.test.ts";
const nameB = "tests\\beta.test.ts";

test("heartbeat names a test file left in flight and counts completed files", async () => {
	const hb = heartbeatPath();
	const state = await drive([
		{ type: "test:dequeue", data: { file: fileA, name: nameA, nesting: 0 } },
		{ type: "test:dequeue", data: { file: fileB, name: nameB, nesting: 0 } },
		{ type: "test:complete", data: { file: fileA, name: nameA, nesting: 0 } },
		// fileB never completes — it is the hung file.
	], hb);
	assert.equal(state.completedFiles, 1, "one file completed");
	assert.equal(state.activeFiles.length, 1, "one file remains in flight");
	assert.equal(state.activeFiles[0].file, fileB, "the in-flight file is named");
	assert.ok(Number.isFinite(state.activeFiles[0].startedAt), "in-flight file carries a start timestamp");
	assert.ok(Number.isFinite(state.lastEventAt), "heartbeat records the last event time");
});

test("heartbeat clears a file from the in-flight set once it completes", async () => {
	const hb = heartbeatPath();
	const state = await drive([
		{ type: "test:dequeue", data: { file: fileA, name: nameA, nesting: 0 } },
		{ type: "test:complete", data: { file: fileA, name: nameA, nesting: 0 } },
	], hb);
	assert.equal(state.completedFiles, 1);
	assert.deepEqual(state.activeFiles, [], "no files remain in flight when all complete");
	assert.deepEqual(state.runningTests, [], "no tests remain running");
});

test("heartbeat tracks best-effort running subtests and drops them on completion", async () => {
	const hb = heartbeatPath();
	const running = await drive([
		{ type: "test:dequeue", data: { file: fileA, name: nameA, nesting: 0 } },
		{ type: "test:start", data: { file: fileA, name: "slow subtest", nesting: 1 } },
		// subtest never passes/fails and the file never completes.
	], hb);
	assert.equal(running.runningTests.length, 1, "an in-flight subtest is recorded");
	assert.equal(running.runningTests[0].name, "slow subtest");
	assert.equal(running.runningTests[0].file, fileA);

	const hb2 = heartbeatPath();
	const done = await drive([
		{ type: "test:dequeue", data: { file: fileA, name: nameA, nesting: 0 } },
		{ type: "test:start", data: { file: fileA, name: "slow subtest", nesting: 1 } },
		{ type: "test:pass", data: { file: fileA, name: "slow subtest", nesting: 1 } },
	], hb2);
	assert.deepEqual(done.runningTests, [], "a settled subtest is dropped from running tests");
});

test("reporter is a silent no-op passthrough when no heartbeat sink is configured", async () => {
	const hb = heartbeatPath();
	// Env unset → reporter must not write anything and must not throw.
	const state = await drive([
		{ type: "test:dequeue", data: { file: fileA, name: nameA, nesting: 0 } },
		{ type: "test:complete", data: { file: fileA, name: nameA, nesting: 0 } },
	], undefined);
	assert.equal(state, undefined, "no heartbeat is produced without a sink");
	assert.equal(existsSync(hb), false, "an unrelated heartbeat path is never written");
});
